#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0; getchar(); // consume newline after T
    for(int tc=0; tc<T; ++tc){
        char s[105], goal[105];
        if(!fgets(s,105,stdin)) return 0; s[strcspn(s,"\n")]=0;
        if(!fgets(goal,105,stdin)) return 0; goal[strcspn(goal,"\n")]=0;
        if(strlen(s)!=strlen(goal)){
            printf("No\n");
            continue;
        }
        char doubled[210];
        strcpy(doubled,s);
        strcat(doubled,s);
        if(strstr(doubled,goal)) printf("Yes\n"); else printf("No\n");
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0; string line; getline(cin,line); // consume endline
    while(T--){
        string s, goal;
        getline(cin,s);
        getline(cin,goal);
        if(s.size()!=goal.size()){
            cout<<"No\n";
            continue;
        }
        string doubled=s+s;
        if(doubled.find(goal)!=string::npos) cout<<"Yes\n"; else cout<<"No\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main{
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        int T=Integer.parseInt(br.readLine().trim());
        StringBuilder out=new StringBuilder();
        for(int tc=0; tc<T; ++tc){
            String s=br.readLine();
            String goal=br.readLine();
            if(s.length()!=goal.length()){
                out.append("No\n");
                continue;
            }
            String doubled=s+s;
            if(doubled.contains(goal)) out.append("Yes\n"); else out.append("No\n");
        }
        System.out.print(out.toString());
    }
}

